<?php
namespace App\Http\Controllers;use App\Domain\WorldMaps\WorldMapReadService;use App\Domain\WorldMaps\WorldMapResolver;use App\Models\Region;use App\Models\World;use App\Models\WorldMap;
final class WorldMapController extends Controller{public function index(WorldMapReadService $read){return view('world-maps.index',$read->index());}public function show(WorldMap $worldMap,WorldMapReadService $read){return view('world-maps.show',['worldMap'=>$read->show($worldMap,view()->shared('navigationCharacter'))]);}public function world(World $world,WorldMapResolver $resolver){return redirect()->route('world-maps.show',$resolver->forWorld($world));}public function region(Region $region,WorldMapResolver $resolver){return redirect()->route('world-maps.show',$resolver->forRegion($region));}}
